function getSeedCanons() {
  return {"_schema_version": 1, "canons": [{"id": "canon-0001-no-emojis", "scope": "sproutlab", "category": "design", "title": "HR-1: No Emojis", "rationale": "All iconography uses the zi() SVG icon system. No emoji characters in application-rendered UI. Emoji in user-supplied text is passthrough only.", "created": "2026-03", "status": "active", "superseded_by": null, "references": ["HR-1"], "_deleted": false, "_deleted_date": null}, {"id": "canon-0002-no-inline-styles", "scope": "sproutlab", "category": "design", "title": "HR-2: No Inline Styles", "rationale": "All styling through CSS classes and CSS custom properties. Never style= attributes. Ensures consistency and theme-ability.", "created": "2026-03", "status": "active", "superseded_by": null, "references": ["HR-2"], "_deleted": false, "_deleted_date": null}, {"id": "canon-0003-no-inline-handlers", "scope": "sproutlab", "category": "architecture", "title": "HR-3: No Inline Event Handlers", "rationale": "All interactivity via data-action delegation. Never onclick= attributes. Single delegation root ensures consistent behavior and easier debugging.", "created": "2026-03", "status": "active", "superseded_by": null, "references": ["HR-3"], "_deleted": false, "_deleted_date": null}, {"id": "canon-0004-eschtml-boundary", "scope": "sproutlab", "category": "architecture", "title": "HR-4: escHtml at All Render Boundaries", "rationale": "All user-supplied text passes through escHtml() before innerHTML. Prevents XSS and ensures safe rendering of arbitrary input.", "created": "2026-03", "status": "active", "superseded_by": null, "references": ["HR-4"], "_deleted": false, "_deleted_date": null}, {"id": "canon-0005-css-tokens", "scope": "sproutlab", "category": "design", "title": "HR-5: All Spacing/Font/Radius via CSS Tokens", "rationale": "Use --sp-*, --fs-*, --r-* tokens exclusively. No magic numbers. Ensures design consistency and enables theme/text-size scaling.", "created": "2026-03", "status": "active", "superseded_by": null, "references": ["HR-5"], "_deleted": false, "_deleted_date": null}, {"id": "canon-0006-data-action-delegation", "scope": "sproutlab", "category": "architecture", "title": "HR-6: data-action Delegation Universal", "rationale": "Every interactive element uses data-action attributes. Single event delegation root. Naming convention: verb-noun or domain-verb-noun.", "created": "2026-03", "status": "active", "superseded_by": null, "references": ["HR-6"], "_deleted": false, "_deleted_date": null}, {"id": "canon-0007-zi-innerhtml", "scope": "sproutlab", "category": "architecture", "title": "HR-7: zi() Returns SVG HTML, Set via innerHTML", "rationale": "zi() returns SVG HTML strings. Always set via .innerHTML, never .textContent. Ensures icons render as SVG elements, not escaped text.", "created": "2026-03", "status": "active", "superseded_by": null, "references": ["HR-7"], "_deleted": false, "_deleted_date": null}, {"id": "canon-0008-coming-soon-toast", "scope": "sproutlab", "category": "design", "title": "HR-8: Stub Features Show Coming Soon Toast", "rationale": "Incomplete or stub features show 'Coming soon' via showQLToast(). Never leave dead buttons or silent no-ops.", "created": "2026-03", "status": "active", "superseded_by": null, "references": ["HR-8"], "_deleted": false, "_deleted_date": null}, {"id": "canon-0009-post-build-qa", "scope": "sproutlab", "category": "process", "title": "HR-9: Post-Build Multi-Round QA Audit", "rationale": "After every build session: multi-round QA continuing until only cosmetic bugs remain. List cosmetic bugs at end. Check all HRs, functional flows, null guards, class coverage, overlay close, escHtml/escAttr.", "created": "2026-03", "status": "active", "superseded_by": null, "references": ["HR-9"], "_deleted": false, "_deleted_date": null}, {"id": "canon-0010-no-text-overflow-ellipsis", "scope": "sproutlab", "category": "design", "title": "HR-10: No text-overflow Ellipsis", "rationale": "Truncated text hides meaning. Wrap, resize, or restructure — never truncate with ellipsis.", "created": "2026-03", "status": "active", "superseded_by": null, "references": ["HR-10"], "_deleted": false, "_deleted_date": null}, {"id": "canon-0011-math-floor-currency", "scope": "sproutlab", "category": "architecture", "title": "HR-11: Math.floor for Currency", "rationale": "All currency values use Math.floor(). Never round up on money — always in the user's favor.", "created": "2026-03", "status": "active", "superseded_by": null, "references": ["HR-11"], "_deleted": false, "_deleted_date": null}, {"id": "canon-0012-timezone-safe-dates", "scope": "sproutlab", "category": "architecture", "title": "HR-12: Timezone-Safe Dates via localDateStr()", "rationale": "All date operations use localDateStr() to avoid timezone offset bugs. Never raw new Date().toISOString().slice(0,10).", "created": "2026-03", "status": "active", "superseded_by": null, "references": ["HR-12"], "_deleted": false, "_deleted_date": null}, {"id": "canon-0013-no-ellipsis", "scope": "global", "category": "design", "title": "No text-overflow Ellipsis (Global)", "rationale": "Promoted from SproutLab HR-10 to global canon. Applies across all projects. Truncation hides meaning — always find a layout solution.", "created": "2026-04", "status": "active", "superseded_by": null, "references": ["canon-0010-no-text-overflow-ellipsis"], "_deleted": false, "_deleted_date": null}, {"id": "canon-0014-eschtml-boundary-global", "scope": "global", "category": "architecture", "title": "escHtml at All Render Boundaries (Global)", "rationale": "All user-supplied text sanitized before innerHTML in every project. Non-negotiable security practice.", "created": "2026-04", "status": "active", "superseded_by": null, "references": ["canon-0004-eschtml-boundary"], "_deleted": false, "_deleted_date": null}, {"id": "canon-0015-data-action-delegation-global", "scope": "global", "category": "architecture", "title": "data-action Delegation (Global)", "rationale": "Event delegation via data-action attributes across all projects. Never inline onclick handlers.", "created": "2026-04", "status": "active", "superseded_by": null, "references": ["canon-0006-data-action-delegation"], "_deleted": false, "_deleted_date": null}, {"id": "canon-0016-defensive-depth", "scope": "global", "category": "architecture", "title": "Defensive Depth", "rationale": "Null guards, fallback defaults, and graceful degradation at every layer. Never assume upstream data is clean. Check before access, fallback before crash.", "created": "2026-04", "status": "active", "superseded_by": null, "references": [], "_deleted": false, "_deleted_date": null}, {"id": "canon-0017-exhaustive-pass4", "scope": "global", "category": "process", "title": "Exhaustive Pass 4 (Bugs Today)", "rationale": "In the 8-pass SPEC_ITERATION_PROCESS, Pass 4 (Bugs Today) must be exhaustive — enumerate every edge case, null state, overflow, and boundary. Never skim.", "created": "2026-04", "status": "active", "superseded_by": null, "references": ["SPEC_ITERATION_PROCESS.md"], "_deleted": false, "_deleted_date": null}, {"id": "canon-0018-shelf-definitions", "scope": "global", "category": "process", "title": "Shelf Definitions", "rationale": "Active = currently being built or maintained. Paused = intentionally on hold, will resume. Archived = complete, read-only reference. Abandoned = stopped, no intent to resume.", "created": "2026-04", "status": "active", "superseded_by": null, "references": [], "_deleted": false, "_deleted_date": null}, {"id": "canon-0019-token-naming", "scope": "global", "category": "design", "title": "Token Naming Convention", "rationale": "CSS tokens: --{prefix}-{category}-{variant}. SproutLab: --sp-*, Codex: --cx-*. Spacing: --sp-N. Font size: --fs-*. Radius: --r-*. Animation: --anim-*. Consistent across all projects.", "created": "2026-04", "status": "active", "superseded_by": null, "references": [], "_deleted": false, "_deleted_date": null}, {"id": "canon-0020-micro-label-deprecated", "scope": "sproutlab", "category": "design", "title": ".micro-label Deprecated", "rationale": "Replaced by .form-label. All instances migrated. Do not reintroduce .micro-label.", "created": "2026-04", "status": "active", "superseded_by": null, "references": [], "_deleted": false, "_deleted_date": null}, {"id": "canon-0021-overlay-anim-sync", "scope": "sproutlab", "category": "design", "title": "OVERLAY_ANIM_MS Must Mirror --anim-overlay", "rationale": "JS constant OVERLAY_ANIM_MS = 300 must always match CSS --anim-overlay: 300ms. Mismatch causes visual glitches on overlay close.", "created": "2026-04", "status": "active", "superseded_by": null, "references": [], "_deleted": false, "_deleted_date": null}, {"id": "canon-0022-keys-constants", "scope": "sproutlab", "category": "architecture", "title": "KEYS Constants for All localStorage Keys", "rationale": "Every localStorage key accessed through the KEYS object. Never bare string keys. Prevents typos and enables easy refactoring.", "created": "2026-03", "status": "active", "superseded_by": null, "references": [], "_deleted": false, "_deleted_date": null}, {"id": "canon-0023-build-sh-only", "scope": "sproutlab", "category": "process", "title": "Never Raw Cat — Always build.sh", "rationale": "Concat order matters (data→core→home→diet→medical→intelligence→start). Always use build.sh, never manual cat. Prevents module ordering bugs.", "created": "2026-04", "status": "active", "superseded_by": null, "references": [], "_deleted": false, "_deleted_date": null}, {"id": "canon-0024-svg-explicit-dimensions", "scope": "global", "category": "design", "title": "SVG Icons Require Explicit width/height Attributes", "rationale": "Inline SVGs without width/height expand to fill their container. All cx() and zi() icons must include width=\"24\" height=\"24\" on the SVG element. CSS constraints alone are insufficient — the attribute is the primary size control.", "created": "2026-04", "status": "active", "superseded_by": null, "references": [], "_deleted": false, "_deleted_date": null}, {"id": "canon-0025-split-from-day-one", "scope": "global", "category": "architecture", "title": "Split Architecture From Day One", "rationale": "SproutLab's Migration M1-M3 (emoji→SVG, inline style extraction, onclick→delegation) proved that splitting a monolith later is a full chapter of work. New projects start with split modules and build.sh concat from the first commit.", "created": "2026-04", "status": "active", "superseded_by": null, "references": ["migration-m1-m2-m3"], "_deleted": false, "_deleted_date": null}, {"id": "canon-0026-natural-page-scroll", "scope": "global", "category": "design", "title": "Natural Page Scroll Over Flex Column Layout", "rationale": "Flex column body with overflow:hidden + scrollable child container creates mobile browser incompatibilities (Chrome localhost scroll bug). Simpler: let body scroll naturally, sticky header, fixed tab bar, padding-bottom on content for tab clearance.", "created": "2026-04", "status": "active", "superseded_by": null, "references": [], "_deleted": false, "_deleted_date": null}, {"id": "canon-0027-mv-over-cp", "scope": "global", "category": "process", "title": "mv Over cp for Downloads → Project", "rationale": "When moving files from ~/storage/downloads/ to project directories, use mv not cp. Keeps downloads clean, prevents stale file confusion, one source of truth.", "created": "2026-04", "status": "active", "superseded_by": null, "references": [], "_deleted": false, "_deleted_date": null}, {"id": "canon-0028-network-first-sw", "scope": "global", "category": "architecture", "title": "Network-First Service Worker for App Shell", "rationale": "Stale-while-revalidate serves cached old versions, requiring manual cache clears after every deploy. Network-first always fetches latest, falls back to cache only when offline. Instant deploys.", "created": "2026-04", "status": "active", "superseded_by": null, "references": [], "_deleted": false, "_deleted_date": null}, {"id": "canon-0029-where-svg-fallback", "scope": "global", "category": "design", "title": ":where() for Zero-Specificity SVG Fallback", "rationale": "Global SVG sizing via :where(#container) svg gives zero specificity, so any class-based rule (.cx-card-title svg, .cx-fab svg) automatically wins. Catches all unconstrained icons without breaking specific overrides.", "created": "2026-04", "status": "active", "superseded_by": "canon-0024-svg-explicit-dimensions", "references": ["canon-0024-svg-explicit-dimensions"], "_deleted": false, "_deleted_date": null}, {"id": "canon-0030-hidden-attr-override", "scope": "global", "category": "design", "title": "CSS display Overrides [hidden] — Always Add [hidden] Rule", "rationale": "HTML hidden attribute sets display:none, but any CSS rule setting display:flex/grid/block overrides it. Always add #element[hidden] { display: none !important } when using display-based layouts on hideable elements.", "created": "2026-04", "status": "active", "superseded_by": null, "references": [], "_deleted": false, "_deleted_date": null}], "rejected_alternatives": [{"id": "rej-0001-horizontal-timeline", "context": "Today So Far card design", "volumes": ["sproutlab"], "rejected": "Horizontal scrolling timeline", "chosen": "Vertical chronological list with warmth gradient bar", "reason": "375px screen width makes horizontal scroll unusable for dense data. Vertical list scans naturally on mobile.", "date": "2026-04-06", "canon_id": null}, {"id": "rej-0002-service-worker-notifications", "context": "CareTickets notification architecture", "volumes": ["sproutlab"], "rejected": "Service Worker push notifications", "chosen": "Main-thread notification architecture with in-app alerts", "reason": "Push notifications require a backend server and VAPID keys. Main-thread approach works offline, no server dependency, simpler permission model.", "date": "2026-04-08", "canon_id": null}, {"id": "rej-0003-multi-file-architecture", "context": "SproutLab architecture split approach", "volumes": ["sproutlab"], "rejected": "ES modules with import/export", "chosen": "Concat build via build.sh — single output file", "reason": "GitHub Pages serves static files. ES modules add complexity (CORS, load order, bundler dependency). Concat keeps single-file PWA simplicity with module organization benefits.", "date": "2026-04-07", "canon_id": null}, {"id": "rej-0004-libre-baskerville", "context": "Codex font selection", "volumes": ["codex"], "rejected": "Libre Baskerville + Source Sans 3", "chosen": "Playfair Display + Work Sans", "reason": "Playfair's high-contrast thick/thin strokes read as library spine lettering. Work Sans has warmer geometry than Source Sans 3, fitting the parchment/leather palette better.", "date": "2026-04-11", "canon_id": null}, {"id": "rej-0005-icon-style-a", "context": "Codex icon set style", "volumes": ["codex"], "rejected": "Style A (thin rounded, stroke 1.5, no fills)", "chosen": "Style C (thin + accent fill — stroke 1.5 with small filled accents)", "reason": "Style C adds subtle filled accents on key icons (bookmark, lock, alert, info, moon) giving a brass-embossed quality that matches the library theme without losing the thin line elegance.", "date": "2026-04-11", "canon_id": null}, {"id": "rej-0006-icon-style-b", "context": "Codex icon set style", "volumes": ["codex"], "rejected": "Style B (medium rounded, stroke 2)", "chosen": "Style C (thin + accent fill)", "reason": "Stroke 2 felt too heavy for the library aesthetic. Style C maintains elegance while improving visual anchoring through selective fills.", "date": "2026-04-11", "canon_id": null}, {"id": "rej-0007-scaling-icons", "context": "Codex text size system — icon behavior", "volumes": ["codex"], "rejected": "Icons scale with text size", "chosen": "Icons stay fixed at 24×24", "reason": "Scaling SVGs with text creates alignment headaches. Fixed icons provide consistent touch targets and layout stability across all text size presets.", "date": "2026-04-11", "canon_id": null}, {"id": "rej-0008-single-file-first", "context": "Codex architecture approach", "volumes": ["codex"], "rejected": "Single file first, split later", "chosen": "Split architecture from day one with build.sh concat", "reason": "SproutLab Migration M1-M3 proved splitting later is painful. Starting split is free since the build.sh workflow is already familiar.", "date": "2026-04-12", "canon_id": "canon-0025-split-from-day-one"}, {"id": "rej-0009-flex-column-body", "context": "Codex page scroll strategy", "volumes": ["codex"], "rejected": "Flex column body with overflow:hidden + scrollable viewContainer", "chosen": "Natural page scroll with sticky header and fixed tab bar", "reason": "Flex column approach broke scrolling on Chrome mobile (localhost). Natural scroll is simpler, works everywhere, matches how most PWAs work.", "date": "2026-04-12", "canon_id": "canon-0026-natural-page-scroll"}, {"id": "rej-0010-first-build-from-memory", "context": "Phase 1 build approach", "volumes": ["codex"], "rejected": "Building from spec memory (Aurelius's first attempt)", "chosen": "Rebuilding from spec codebase reference files", "reason": "First build had wrong element IDs, action names, store field names, and was missing scroll preservation, dirty form detection, escape handlers, error logging, and localStorage test. The 452-bug spec existed for a reason.", "date": "2026-04-12", "canon_id": null}, {"id": "rej-0011-stale-while-revalidate-sw", "context": "Codex service worker caching strategy", "volumes": ["codex"], "rejected": "Stale-while-revalidate for app shell", "chosen": "Network-first with cache fallback", "reason": "SWR serves cached old version first, requiring manual cache clears after every deploy. Network-first always gets latest, only uses cache when offline.", "date": "2026-04-12", "canon_id": "canon-0028-network-first-sw"}, {"id": "rej-0012-natural-scroll-reversed", "context": "Codex scroll strategy (Phase 2 reversal)", "volumes": ["codex"], "rejected": "Natural page scroll (Phase 1 decision)", "chosen": "Flex column body with overflow:hidden + scrollable viewContainer", "reason": "Phase 1 used natural scroll to avoid Chrome localhost bug. Phase 2 needed body as flex container for viewContainer flex:1 to work. The original Chrome bug was environment-specific; flex layout is the correct pattern for app-shell PWAs with fixed header/tab bar.", "date": "2026-04-12", "canon_id": null}], "apocrypha": []};
}

